import time
import threading
from enum import Enum, auto

class CBState(Enum):
    CLOSED    = auto()
    OPEN      = auto()
    HALF_OPEN = auto()

class CircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 5,
        recovery_timeout: float = 30.0,
        half_open_max_calls: int = 1,
    ):
        self.failure_threshold   = failure_threshold
        self.recovery_timeout    = recovery_timeout
        self.half_open_max_calls = half_open_max_calls

        self._state          = CBState.CLOSED
        self._failure_count  = 0
        self._last_opened_at = 0.0
        self._half_open_calls = 0
        self._lock           = threading.Lock()

    @property
    def state(self) -> CBState:
        with self._lock:
            if self._state == CBState.OPEN:
                if time.monotonic() - self._last_opened_at >= self.recovery_timeout:
                    self._state = CBState.HALF_OPEN
                    self._half_open_calls = 0
            return self._state

    def call(self, fn, *args, **kwargs):
        state = self.state
        if state == CBState.OPEN:
            raise RuntimeError("Circuit is OPEN — call blocked")
        if state == CBState.HALF_OPEN:
            with self._lock:
                if self._half_open_calls >= self.half_open_max_calls:
                    raise RuntimeError("Circuit is HALF-OPEN — probe limit reached")
                self._half_open_calls += 1
        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise

    def _on_success(self):
        with self._lock:
            self._failure_count = 0
            self._state = CBState.CLOSED

    def _on_failure(self):
        with self._lock:
            self._failure_count += 1
            if (self._state in {CBState.CLOSED, CBState.HALF_OPEN}
                    and self._failure_count >= self.failure_threshold):
                self._state = CBState.OPEN
                self._last_opened_at = time.monotonic()

cb = CircuitBreaker(failure_threshold=5, recovery_timeout=30.0)

def protected_llm_call(query: str) -> str:
