from langgraph.graph import StateGraph, END
from typing import TypedDict

llm_breaker = CircuitBreaker(failure_threshold=3, recovery_timeout=60.0)

class State(TypedDict):
    query: str
    result: str
    circuit_open: bool

def llm_node(state: State) -> dict:
    try:
        result = llm_breaker.call(lambda: llm.invoke(state["query"]).content)
        return {"result": result, "circuit_open": False}
    except RuntimeError as e:
        if "OPEN" in str(e):
            return {"result": "", "circuit_open": True}
        raise   # real exception — let LangGraph handle it

def route(state: State) -> str:
    return "degraded" if state.get("circuit_open") else "format"

def degraded_node(state: State) -> dict:
    return {"result": "Service temporarily unavailable — using cached data."}

def format_node(state: State) -> dict:
    return {"result": f"Result: {state['result']}"}

builder = StateGraph(State)
builder.add_node("llm",      llm_node)
builder.add_node("degraded", degraded_node)
builder.add_node("format",   format_node)
builder.set_entry_point("llm")
builder.add_conditional_edges("llm", route, {"degraded": "degraded", "format": "format"})
builder.add_edge("degraded", END)
builder.add_edge("format",   END)
graph = builder.compile()

from collections import deque
import time

class SlidingWindowCircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 5,
        window_seconds: float = 60.0,
        recovery_timeout: float = 30.0,
    ):
        self.failure_threshold = failure_threshold
        self.window_seconds    = window_seconds
        self.recovery_timeout  = recovery_timeout
        self._failures         = deque()  # timestamps of recent failures
        self._state            = CBState.CLOSED
        self._opened_at        = 0.0
        self._lock             = threading.Lock()

    def _prune(self):
        cutoff = time.monotonic() - self.window_seconds
        while self._failures and self._failures[0] < cutoff:
            self._failures.popleft()

    def _on_failure(self):
        with self._lock:
            now = time.monotonic()
            self._failures.append(now)
            self._prune()
            if len(self._failures) >= self.failure_threshold:
                self._state     = CBState.OPEN
                self._opened_at = now

    def _on_success(self):
        with self._lock:
            if self._state == CBState.HALF_OPEN:
                self._state = CBState.CLOSED
                self._failures.clear()

    def call(self, fn, *args, **kwargs):
        with self._lock:
            if self._state == CBState.OPEN:
                if time.monotonic() - self._opened_at >= self.recovery_timeout:
                    self._state = CBState.HALF_OPEN
                else:
                    raise RuntimeError("Circuit OPEN")
        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception:
            self._on_failure()
            raise

