import pytest
import time

def test_opens_after_threshold():
    cb = CircuitBreaker(failure_threshold=3, recovery_timeout=60.0)
    def fail(): raise ConnectionError("down")
    for _ in range(3):
        try: cb.call(fail)
        except ConnectionError: pass
    assert cb.state == CBState.OPEN

def test_fast_fails_when_open():
    cb = CircuitBreaker(failure_threshold=1, recovery_timeout=60.0)
    try: cb.call(lambda: (_ for _ in ()).throw(ConnectionError("down")))
    except ConnectionError: pass
    with pytest.raises(RuntimeError, match="OPEN"):
        cb.call(lambda: "should not run")

def test_transitions_to_half_open_after_timeout():
    cb = CircuitBreaker(failure_threshold=1, recovery_timeout=0.05)
    try: cb.call(lambda: (_ for _ in ()).throw(ConnectionError()))
    except ConnectionError: pass
    time.sleep(0.1)
    assert cb.state == CBState.HALF_OPEN

def test_closes_after_successful_probe():
    cb = CircuitBreaker(failure_threshold=1, recovery_timeout=0.05)
    try: cb.call(lambda: (_ for _ in ()).throw(ConnectionError()))
    except ConnectionError: pass
    time.sleep(0.1)
    cb.call(lambda: "ok")   # probe succeeds
    assert cb.state == CBState.CLOSED

def call_with_retry_and_breaker(fn, breaker: CircuitBreaker,
                                max_retries: int = 3, base_delay: float = 1.0):
    import time
    # Will raise RuntimeError immediately if circuit is OPEN
    # (no retries attempted — fast fail)
    if breaker.state == CBState.OPEN:
        raise RuntimeError("Circuit OPEN — skipping retries")

    last_exc = None
    for attempt in range(max_retries):
        try:
            return breaker.call(fn)   # breaker tracks success/failure
        except RuntimeError as e:
            if "OPEN" in str(e):
                raise   # circuit just opened mid-retry — abort
            raise
        except Exception as exc:
            last_exc = exc
            if attempt < max_retries - 1:
                time.sleep(min(base_delay * (2 ** attempt), 30))
    raise last_exc
